        @Override
        public boolean isToBeProcessed(CtInvocation<?> candidate) {
            // 1. Name Check
            if (!TARGET_METHOD_NAME.equals(candidate.getExecutable().getSimpleName())) {
                return false;
            }

            // 2. Argument Count Check (Example: expecting 1 argument)
            // TODO: Adjust based on the diff (e.g., arguments removed/added)
            if (candidate.getArguments().size() != 1) {
                return false;
            }

            // 3. Type Check (Defensive for NoClasspath)
            CtExpression<?> arg = candidate.getArguments().get(0);
            CtTypeReference<?> type = arg.getType();

            // Example Safety: If type is known and matches the NEW type, skip (idempotency).
            if (type != null && type.getQualifiedName().contains("NewType")) {
                return false;
            }

            // 4. Owner Check (Relaxed string matching for NoClasspath)
            CtTypeReference<?> owner = candidate.getExecutable().getDeclaringType();
            if (owner != null 
                && !owner.getQualifiedName().contains(TARGET_CLASS_SUBSTRING) 
                && !owner.getQualifiedName().equals("<unknown>")) {
                return false;
            }

            return true;
        }

